    def _encode_disk_value(self, value: Any) -> Any:
        """Serialize a value for on-disk storage, compressing it if compression is enabled.

        When compression is disabled (the default), the value is stored as-is, matching the
        cache's original on-disk format exactly.
        """
        if self.compress is None:
            return value

        payload = pickle.dumps(value)
        codec = _COMPRESS_NAME_TO_CODEC[self.compress]
        if codec == _CODEC_GZIP:
            payload = gzip.compress(payload)
        elif codec == _CODEC_ZLIB:
            payload = zlib.compress(payload)
        return _CACHE_MAGIC + bytes([codec]) + payload

    def _decode_disk_value(self, raw: Any) -> Any:
        """Deserialize a value read from the on-disk cache.

        If `raw` carries the DSPy cache magic header, it is decompressed (if needed) and
        unpickled. Otherwise, it's treated as a legacy raw pickle value (i.e., a value written
        before this feature existed, or while compression was disabled), and is returned unchanged
        since diskcache has already deserialized it.
        """
        if not isinstance(raw, bytes) or raw[:4] != _CACHE_MAGIC:
            return raw

        codec = raw[4]
        payload = raw[5:]
        decompress = _CODEC_TO_DECOMPRESS.get(codec)
        if decompress is not None:
            payload = decompress(payload)
        return pickle.loads(payload)"}

